function getCookie(e){const o=document.cookie.split(";").find((o=>o.startsWith(e+"=")));return o?decodeURIComponent(o.split("=")[1]):null}function extractAuthDataFromCookie(){const e=getCookie("auth");if(!e)return console.error("auth cookie not found."),null;try{const o=decodeURIComponent(e),n=JSON.parse(o);return{userId:n.userId,accessToken:n.accessToken}}catch(e){return console.error("Error parsing auth cookie:",e),null}}function formatDate(e){return new Date(e).toLocaleString()}async function fetchSessionInfo(e,o){try{const n=await fetch("https://www.ambassadoribet.com/_internal/gql",{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${o}`},body:JSON.stringify({query:" query SessionConnection($userId:ID){sessionConnection(userId:$userId,last:15){edges{node{ip os browser createdAt}}}}",variables:{userId:e}})});if(!n.ok)throw new Error(`HTTP error! Status:${n.status}`);const s=await n.json();return s?.data?.sessionConnection?.edges||[]}catch(e){return console.error("Error fetching session information:",e),[]}}function renderSessionInfo(e){const o=document.getElementById("session-list");o&&(o.innerHTML="",0!==e.length?e.forEach((e=>{const{ip:n,os:s,browser:t,createdAt:r}=e.node,a=document.createElement("li");a.innerHTML=` <p><span class="label">IP:</span> ${n}</p> <p><span class="label">OS:</span> ${s}</p> <p><span class="label">Browser:</span> ${t}</p> <p><span class="label">Time:</span> ${formatDate(r)}</p> `,o.appendChild(a)})):o.innerHTML="<li>No session data found.</li>")}async function loadSessionData(){const e=extractAuthDataFromCookie();if(!e||!e.userId||!e.accessToken)return void console.error("Failed to retrieve user ID or access token from cookie.");const{userId:o,accessToken:n}=e;renderSessionInfo(await fetchSessionInfo(o,n))}